/** Normaliza texto para busca no calendário (minúsculas, sem acentos). */
function normTextoBuscaCal(s: string) {
  return s.trim().toLowerCase().normalize('NFD').replace(/\p{M}/gu, '');
}

type JsPDFDoc = InstanceType<typeof jsPDF>;

/** Linha da assinatura no rodapé (jsPDF A4 padrão, margem superior). Corpo deve terminar acima. */
const PDF_REQ_EXAMES_Y_ASSINATURA = 250;
/** Margem esquerda e direita úteis para lista de exames (alinhado ao restante do PDF). */
const PDF_REQ_EXAMES_X_INICIO = 20;
const PDF_REQ_EXAMES_X_FIM = 190;

/** Logo canto superior direito: PDFs de prescrição médica e recibo (identidade Método Emagrecer). Escala mantém proporção (não estica). */
const PDF_PRESCRICAO_LOGO_SRC = '/icones/logotipo-metodo-28.png';
const PDF_PRESCRICAO_LOGO_MAX_W_MM = 52;
const PDF_PRESCRICAO_LOGO_MAX_H_MM = 22;
const PDF_PRESCRICAO_LOGO_Y_MM = 7;

function pdfPrescricaoLogoLayoutFromImage(img: HTMLImageElement): { x: number; y: number; w: number; h: number } {
  const maxW = PDF_PRESCRICAO_LOGO_MAX_W_MM;
  const maxH = PDF_PRESCRICAO_LOGO_MAX_H_MM;
  const nw = img.naturalWidth;
  const nh = img.naturalHeight;
  let w: number;
  let h: number;
  if (!nw || !nh || nw <= 0 || nh <= 0) {
    w = maxW;
    h = Math.min(maxH, maxW * (9 / 28));
  } else {
    const ratio = nh / nw;
    w = maxW;
    h = w * ratio;
    if (h > maxH) {
      h = maxH;
      w = h / ratio;
    }
  }
  const x = 190 - w - 10;
  const y = PDF_PRESCRICAO_LOGO_Y_MM;
  return { x, y, w, h };
}

/** Safari iOS bloqueia `doc.save()` após `await` no mesmo handler — logo deve estar em cache antes do toque. */
let prescricaoLogoPdfCache: HTMLImageElement | null = null;
let prescricaoLogoPdfLoadStarted = false;

function preloadPrescricaoLogoForPdf(): void {
  if (typeof window === 'undefined') return;
  const existing = prescricaoLogoPdfCache;
  if (existing?.complete && existing.naturalWidth > 0) return;
  if (prescricaoLogoPdfLoadStarted) return;
  prescricaoLogoPdfLoadStarted = true;
  const img = new Image();
  img.crossOrigin = 'anonymous';
  img.onload = () => {
    prescricaoLogoPdfCache = img;
  };
  img.onerror = () => {
    prescricaoLogoPdfCache = null;
    prescricaoLogoPdfLoadStarted = false;
  };
  img.src = PDF_PRESCRICAO_LOGO_SRC;
}

function addPrescricaoLogoToPdfSync(doc: JsPDFDoc): void {
  const img = prescricaoLogoPdfCache;
  if (img && img.complete && img.naturalWidth > 0) {
    try {
      const { x, y, w, h } = pdfPrescricaoLogoLayoutFromImage(img);
      doc.addImage(img, 'PNG', x, y, w, h);
      return;
    } catch {
      /* texto abaixo */
    }
  }
  doc.setFontSize(9);
  doc.setFont('helvetica', 'bold');
  doc.text('Oftware', 180, 15, { align: 'right' });
}

/** Até 10 exames: 1 coluna; 11–20: 2 colunas iguais; acima de 20: 3 colunas iguais (sempre distribuição equilibrada). */
function numColunasExamesPdfPorQuantidade(n: number): number {
  if (n <= 10) return 1;
  if (n <= 20) return 2;
  return 3;
}

function dividirExamesEmKColunasEquilibradas(items: string[], k: number): string[][] {
  const n = items.length;
  if (k <= 1) return [items];
  const base = Math.floor(n / k);
  const rem = n % k;
  const cols: string[][] = [];
  let idx = 0;
  for (let c = 0; c < k; c++) {
    const len = base + (c < rem ? 1 : 0);
    cols.push(items.slice(idx, idx + len));
    idx += len;
  }
  return cols;
}

/** Posição X inicial de cada coluna: faixas de igual largura entre PDF_REQ_EXAMES_X_INICIO e PDF_REQ_EXAMES_X_FIM. */
function posicoesXColunasPdfExames(k: number): number[] {
  const left = PDF_REQ_EXAMES_X_INICIO;
  const W = PDF_REQ_EXAMES_X_FIM - left;
  if (k <= 1) return [left + 2];
  return Array.from({ length: k }, (_, c) => left + (W * c) / k + 2);
}

/** Altura estimada do quadro de hipótese; 0 se não houver texto. */
function estimarAlturaQuadroHipotesePdf(doc: JsPDFDoc, hipoteseTexto: string): number {
  const texto = hipoteseTexto.trim();
  if (!texto) return 0;
  const largura = 170;
  const pad = 4;
  doc.setFontSize(9);
  const linhas = doc.splitTextToSize(texto, largura - pad * 2);
  const linhasMinReservadas = 3;
  const alturaTitulo = 7;
  const alturaLinhaTxt = 4.5;
  const numLinhas = Math.max(linhas.length, linhasMinReservadas);
  return alturaTitulo + pad + numLinhas * alturaLinhaTxt + pad;
}

/**
 * Lista de exames: 1 / 2 ou 3 colunas conforme quantidade; colunas com mesma largura.
 * y máx. = yMaxFimBlocoExames (base da lista + nº de linhas × entrelinha).
 */
function desenharListaExamesSolicitacaoPdf(
  doc: JsPDFDoc,
  yInicio: number,
  todosExames: string[],
  yMaxFimBlocoExames: number
): number {
  if (todosExames.length === 0) return yInicio;
  const k = numColunasExamesPdfPorQuantidade(todosExames.length);
  const colunas = dividirExamesEmKColunasEquilibradas(todosExames, k);
  const xs = posicoesXColunasPdfExames(k);
  const maxRows = Math.max(...colunas.map((col) => col.length), 0);
  let fontSize = 9;
  let lineH = 5;
  const minFont = 6.5;
  const minLineH = 3.4;
  doc.setFont('helvetica', 'normal');
  for (;;) {
    doc.setFontSize(fontSize);
    const blocoAltura = maxRows * lineH;
    if (yInicio + blocoAltura <= yMaxFimBlocoExames || (fontSize <= minFont && lineH <= minLineH)) {
      for (let r = 0; r < maxRows; r++) {
        const yLine = yInicio + r * lineH;
        for (let c = 0; c < k; c++) {
          if (r < colunas[c].length) doc.text(`• ${colunas[c][r]}`, xs[c], yLine);
        }
      }
      return yInicio + blocoAltura;
    }
    fontSize = Math.max(minFont, fontSize - 0.5);
    lineH = Math.max(minLineH, lineH - 0.35);
  }
}

/**
 * Quadro “Hipótese Diagnóstica” imediatamente acima da faixa do rodapé (sem nova página).
 * Ajusta linhas em branco mínimas se faltar espaço até yMaxBottom.
 */
function desenharHipoteseDiagnosticaSolicitacaoPdf(
  doc: JsPDFDoc,
  yPos: number,
  hipoteseTexto: string,
  darkColor: [number, number, number],
  yMaxBottom: number
): number {
  const margem = 20;
  const largura = 170;
  const pad = 3;
  doc.setFontSize(9);
  doc.setFont('helvetica', 'normal');
  const texto = hipoteseTexto.trim();
  if (!texto) return yPos;
  let linhas = doc.splitTextToSize(texto, largura - pad * 2);
  const alturaTitulo = 7;
  let alturaLinhaTxt = 4.5;
  let linhasMinReservadas = 3;
  let numLinhas = Math.max(linhas.length, linhasMinReservadas);
  let boxH = alturaTitulo + pad + numLinhas * alturaLinhaTxt + pad;
  while (yPos + boxH > yMaxBottom) {
    if (linhasMinReservadas > linhas.length) {
      linhasMinReservadas -= 1;
    } else if (alturaLinhaTxt > 3.2) {
      alturaLinhaTxt = Math.max(3.2, alturaLinhaTxt - 0.35);
    } else {
      break;
    }
    numLinhas = Math.max(linhas.length, linhasMinReservadas);
    boxH = alturaTitulo + pad + numLinhas * alturaLinhaTxt + pad;
  }
  doc.setDrawColor(...darkColor);
  doc.setLineWidth(0.35);
  doc.rect(margem, yPos, largura, boxH);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...darkColor);
  doc.text('Hipótese Diagnóstica', margem + pad, yPos + alturaTitulo);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9);
  let ly = yPos + alturaTitulo + pad + 4;
  if (linhas.length > 0) {
    linhas.forEach((line) => {
      doc.text(line, margem + pad, ly);
      ly += alturaLinhaTxt;
    });
  }
  return yPos + boxH + 4;
}

/** Todas as chaves listadas no modal (com label válido via getLabRange) para o sexo/data do paciente. */
function coletarTodasChavesExamesDisponiveisNoModal(
  sexo: Sex | undefined,
  dataNascimento: Date | string | undefined,
  labOrder: Record<string, string[]> = labOrderBySection,
  limitOverrides?: LabLimitOverrides | null
): string[] {
  const keys: string[] = [];
  for (const campos of Object.values(labOrder)) {
    if (!Array.isArray(campos)) continue;
    for (const campoKey of campos) {
      const rangeToUse = getLabRange(campoKey, sexo as Sex, dataNascimento, limitOverrides);
      if (rangeToUse?.label) keys.push(campoKey);
    }
  }
  return keys;
}

