function normalizar(s?: string) {
  return (s || '').toLowerCase();
}

/** Valores de pagamento de paciente calculados a partir das parcelas. Sem parcelas = tudo zerado. */
function getValoresPacienteDeParcelas(pag: PagamentoPaciente | null | undefined): { valorTotal: number; valorPago: number; valorPendente: number } {
  if (!pag?.parcelas?.length) return { valorTotal: 0, valorPago: 0, valorPendente: 0 };
  const valorTotal = pag.parcelas.reduce((s, p) => s + (p.valor || 0), 0);
  const valorPago = pag.parcelas.filter((p) => p.status === 'paga').reduce((s, p) => s + (p.valor || 0), 0);
  return { valorTotal, valorPago, valorPendente: valorTotal - valorPago };
}

/** Status de pagamento de paciente a partir das parcelas. Sem parcelas = sempre Aberto. */
function getStatusPagamentoPaciente(pag: PagamentoPaciente | null | undefined): 'pago' | 'iniciou_pagamento' | 'em_aberto' {
  if (!pag?.parcelas?.length) return 'em_aberto';
  const todasPagas = pag.parcelas.every((p) => p.status === 'paga');
  const algumaPagaComPendente = pag.parcelas.some((p) => p.status === 'paga') && pag.parcelas.some((p) => p.status === 'pendente' || p.status === 'atrasada');
  return todasPagas ? 'pago' : algumaPagaComPendente ? 'iniciou_pagamento' : 'em_aberto';
}

/**
 * Semana 1: peso do registro substitui medidasIniciais.peso; circunferência substitui medidasIniciais.circunferenciaAbdominal quando informada.
 * Recalcula IMC se houver altura nas medidas iniciais.
 */
function pacienteComMedidasIniciaisAtualizadasPelaSemana1(
  paciente: PacienteCompleto,
  weekIndex: number,
  pesoRegistro: number | undefined,
  circunferenciaRegistro: number | undefined
): PacienteCompleto {
  if (weekIndex !== 1) return paciente;
  const dc = paciente.dadosClinicos || ({} as DadosClinicos);
  const prev = dc.medidasIniciais;
  const pesoNovo =
    pesoRegistro != null && !Number.isNaN(pesoRegistro) && pesoRegistro > 0
      ? pesoRegistro
      : prev?.peso ?? 0;
  const circNova =
    circunferenciaRegistro != null && !Number.isNaN(circunferenciaRegistro)
      ? circunferenciaRegistro
      : prev?.circunferenciaAbdominal ?? 0;
  const altura = prev?.altura ?? 0;
  let imc = prev?.imc ?? 0;
  if (altura > 0 && pesoNovo > 0) {
    const h = altura / 100;
    imc = Number((pesoNovo / (h * h)).toFixed(1));
  }
  return {
    ...paciente,
    dadosClinicos: {
      ...dc,
      medidasIniciais: {
        peso: pesoNovo,
        altura,
        imc,
        circunferenciaAbdominal: circNova,
      },
    },
  };
}

type VendaAgrupada = { label: string; data: Date; valorTotal: number; valorPago: number; valorPendente: number };

/** Agrupa parcelas por venda: Venda Inicial = parcelas sem dataVenda; cada parcela com dataVenda inicia nova venda (Venda 2, Venda 3...). */
function agruparParcelasPorVenda(
  parcelas: ParcelaPagamento[],
  dataVendaFallback: Date,
  toDate: (v: unknown) => Date | null = (v) => {
    if (!v) return null;
    if (v instanceof Date) return v;
    const t = (v as { toDate?: () => Date })?.toDate?.();
    if (t) return t;
    const d = new Date(v as string | number);
    return isNaN(d.getTime()) ? null : d;
  }
): VendaAgrupada[] {
  const filtered = parcelas.filter((p) => (p.valor || 0) > 0);
  if (!filtered.length) return [];

  const vendas: VendaAgrupada[] = [];
  let vendaIdx = 0;
  let i = 0;

  // 1) Venda Inicial: parcelas sem dataVenda no início
  if (!filtered[0].dataVenda) {
    let vt = 0,
      vp = 0;
    while (i < filtered.length && !filtered[i].dataVenda) {
      const val = filtered[i].valor || 0;
      vt += val;
      if (filtered[i].status === 'paga') vp += val;
      i++;
    }
    vendas.push({
      label: 'Venda Inicial',
      data: dataVendaFallback,
      valorTotal: vt,
      valorPago: vp,
      valorPendente: vt - vp,
    });
    vendaIdx = 1;
  }

  // 2) Venda 2, 3, ...: cada parcela com dataVenda + seguintes até a próxima dataVenda
  while (i < filtered.length) {
    const primeira = filtered[i];
    const dataVenda = primeira.dataVenda ? toDate(primeira.dataVenda) : null;
    const data = dataVenda || dataVendaFallback;
    let vt = primeira.valor || 0;
    let vp = primeira.status === 'paga' ? primeira.valor || 0 : 0;
    i++;

    while (i < filtered.length && !filtered[i].dataVenda) {
      const val = filtered[i].valor || 0;
      vt += val;
      if (filtered[i].status === 'paga') vp += val;
      i++;
    }

    vendaIdx++;
    vendas.push({
      label: `Venda ${vendaIdx}`,
      data,
      valorTotal: vt,
      valorPago: vp,
      valorPendente: vt - vp,
    });
  }

  return vendas;
}

function getSubtipoPrescricao(p: { nome?: string; descricao?: string; observacoes?: string }): PrescricaoSubtipo {
  const rawNome = (p.nome || '').trim();
  if (rawNome.includes(' — ')) {
    const prefix = rawNome.split(' — ')[0].trim();
    const match = SUBTIPOS_ORDER.find((s) => s === prefix);
    if (match) return match;
  }

  const nome = normalizar(p.nome);
  const desc = normalizar(p.descricao);
  const obs = normalizar(p.observacoes);
  const txt = `${nome} ${desc} ${obs}`;

  if (txt.includes('tirzepatida') || txt.includes('mounjaro') || txt.includes('zepbound') || txt.includes('base do tratamento')) return 'Base do Tratamento';
  if (txt.includes('probiótico') || txt.includes('probiotico') || txt.includes('inulina') || txt.includes('fos') || txt.includes('constip') || txt.includes('náuse') || txt.includes('nause') || txt.includes('empach') || txt.includes('magnésio') || txt.includes('magnesio')) return 'Gastrointestinal';
  if (txt.includes('hmb') || txt.includes('whey') || txt.includes('leucina') || txt.includes('creatina') || txt.includes('massa magra') || txt.includes('sarcopen')) return 'Massa Magra & Performance';
  if (txt.includes('berberina') || txt.includes('cromo') || txt.includes('insulina') || txt.includes('resist') || txt.includes('glic') || txt.includes('homa')) return 'Metabólico / Glicêmico';
  if (txt.includes('vitamina d') || txt.includes('colecalciferol') || txt.includes('b12') || txt.includes('metilcobalamina') || txt.includes('zinco') || txt.includes('selênio') || txt.includes('selenio') || txt.includes('ferrit')) return 'Micronutrientes';
  if (txt.includes('sono') || txt.includes('insônia') || txt.includes('insonia') || txt.includes('melaton') || txt.includes('teanina') || txt.includes('glicina') || txt.includes('compuls')) return 'Sono & Comportamento';
  if (txt.includes('silimarina') || txt.includes('colina') || txt.includes('inositol') || txt.includes('esteat') || txt.includes('tgo') || txt.includes('tgp') || txt.includes('ggt') || txt.includes('omega') || txt.includes('coq10') || txt.includes('ldl') || txt.includes('hdl') || txt.includes('trig')) return 'Hepático / Cardiometabólico';
  return 'Outros';
}

function groupBySubtipo<T extends { nome?: string; descricao?: string; observacoes?: string }>(arr: T[]) {
  const map = new Map<PrescricaoSubtipo, T[]>();
  for (const p of arr) {
    const subtipo = getSubtipoPrescricao(p);
    map.set(subtipo, [...(map.get(subtipo) || []), p]);
  }
  return SUBTIPOS_ORDER.filter((k) => (map.get(k) || []).length > 0).map((k) => ({ subtipo: k, items: map.get(k)! }));
}

/** Título para exibição na lista: remove prefixo "SUBTIPO — " quando existir. */
function getTituloExibicao(nome: string): string {
  const n = (nome || '').trim();
  if (n.includes(' — ')) return n.split(' — ')[1]?.trim() || n;
  return n;
}

const PRESCRICAO_RECIBO_GRUPO_LABEL = 'Recibo Médico';

function isReciboMedicoPrescricao(p: { tipoDocumento?: Prescricao['tipoDocumento'] } | null | undefined): boolean {
  return !!p && p.tipoDocumento === 'recibo_medico';
}

function parseValorConsultaBRLInput(raw: string): number | null {
  let s = (raw || '').trim().replace(/\s/g, '');
  if (!s) return null;
  s = s.replace(/R\$\s?/gi, '');
  if (s.includes(',') && s.includes('.')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }
  const n = parseFloat(s);
  if (Number.isNaN(n) || n < 0) return null;
  return n;
}

function isDataReciboISOValid(iso: string): boolean {
  if (!iso || !/^\d{4}-\d{2}-\d{2}$/.test(iso.trim())) return false;
  const [y, m, d] = iso.trim().split('-').map(Number);
  const dt = new Date(y, m - 1, d);
  return dt.getFullYear() === y && dt.getMonth() === m - 1 && dt.getDate() === d;
}

function formatDataReciboISOToPtBr(iso: string): string {
  if (!isDataReciboISOValid(iso)) return '';
  const [Ty, Tm, Td] = iso.trim().split('-').map(Number);
  return new Date(Ty, Tm - 1, Td).toLocaleDateString('pt-BR');
}

function prescricaoFormFromEntity(p: Prescricao): {
  nome: string;
  descricao: string;
  itens: PrescricaoItem[];
  observacoes: string;
  valorConsulta: string;
  dataRecibo: string;
  reciboDocumentoProfissional: 'omitir' | 'cpf' | 'cnpj';
} {
  const docProf =
    p.reciboDocumentoProfissional === 'cpf' || p.reciboDocumentoProfissional === 'cnpj'
      ? p.reciboDocumentoProfissional
      : 'omitir';
  return {
    nome: p.nome,
    descricao: p.descricao || '',
    itens: p.itens || [],
    observacoes: p.observacoes || '',
    valorConsulta:
      p.valorConsulta != null && !Number.isNaN(Number(p.valorConsulta)) ? String(p.valorConsulta) : '',
    dataRecibo: p.dataRecibo && isDataReciboISOValid(p.dataRecibo) ? p.dataRecibo : '',
    reciboDocumentoProfissional: docProf,
  };
}

// Componente Modal Manual de Leads
function ManualLeadsModal({ 
  onClose, 
  statusConfig 
}: { 
  onClose: () => void;
  statusConfig: Record<LeadMedicoStatus, { label: string; color: string; bgColor: string }>;
}) {
  const statusOrder: LeadMedicoStatus[] = ['nao_qualificado', 'enviado_contato', 'contato_feito', 'em_tratamento', 'excluido', 'concluido'];
  const [currentStep, setCurrentStep] = useState(0);
  
  const stepInfo = [
    {
      status: 'nao_qualificado' as LeadMedicoStatus,
      title: '1. Não Qualificado',
      description: 'Lead inicial que ainda não foi qualificado. É aqui que todos os novos leads começam.',
      advantages: [
        'Organização: Separa leads novos de leads em processo',
        'Controle: Visualização clara de quem ainda precisa de atenção inicial',
        'Conversão: Identifica oportunidades que precisam ser qualificadas'
      ],
      nextAction: 'Após revisar, mova o lead para "Enviado Contato" usando a seta →'
    },
    {
      status: 'enviado_contato' as LeadMedicoStatus,
      title: '2. Enviado Contato',
      description: 'Você já enviou uma mensagem de contato inicial ao lead. Aguardando resposta.',
      advantages: [
        'Organização: Identifica leads que já receberam o primeiro contato',
        'Controle: Evita duplicação de contatos e mensagens',
        'Conversão: Seguimento focado em quem já demonstrou interesse inicial'
      ],
      nextAction: 'Quando receber resposta, mova para "Contato Feito" usando a seta →'
    },
    {
      status: 'contato_feito' as LeadMedicoStatus,
      title: '3. Contato Feito',
      description: 'Lead respondeu ao contato e está em processo de qualificação ativa.',
      advantages: [
        'Organização: Leads em conversação ativa separados dos demais',
        'Controle: Facilita acompanhamento de negociações em andamento',
        'Conversão: Foco nos leads mais próximos da conversão'
      ],
      nextAction: 'Ao aceitar o paciente, mova para "Em Tratamento" usando a seta →'
    },
    {
      status: 'em_tratamento' as LeadMedicoStatus,
      title: '4. Em Tratamento',
      description: 'Lead convertido! O paciente foi aceito e está em tratamento ativo.',
      advantages: [
        'Organização: Separa pacientes ativos de leads em qualificação',
        'Controle: Acompanhamento claro do pipeline de conversão',
        'Conversão: Métrica final do sucesso do processo de qualificação'
      ],
      nextAction: 'Paciente convertido com sucesso! 🎉'
    },
    {
      status: 'excluido' as LeadMedicoStatus,
      title: '5. Excluído',
      description: 'Lead que foi descartado (não qualificado, não interessado, etc.).',
      advantages: [
        'Organização: Mantém o pipeline limpo removendo leads não viáveis',
        'Controle: Histórico de leads descartados para análise',
        'Conversão: Foco apenas em leads com potencial real'
      ],
      nextAction: 'Leads excluídos não aparecem no pipeline principal'
    },
    {
      status: 'concluido' as LeadMedicoStatus,
      title: '6. Concluído',
      description: 'Paciente que concluiu o tratamento com sucesso.',
      advantages: [
        'Organização: Separa pacientes que finalizaram o tratamento',
        'Controle: Histórico completo de pacientes concluídos',
        'Conversão: Métrica de sucesso do tratamento'
      ],
      nextAction: 'Tratamento finalizado com sucesso! 🎉'
    }
  ];

  const currentStatus = stepInfo[currentStep].status;
  const currentIndex = statusOrder.indexOf(currentStatus);
  
  // Ref para o container do pipeline para fazer scroll
  const pipelineScrollRef = useRef<HTMLDivElement>(null);
  // Ref para a seção de informações para fazer scroll para o topo
  const infoSectionRef = useRef<HTMLDivElement>(null);

  // Função para fazer scroll até a coluna atual
  const scrollToCurrentColumn = (step: number) => {
    if (pipelineScrollRef.current) {
      const container = pipelineScrollRef.current;
      const cards = container.querySelectorAll('[data-pipeline-card]');
      if (cards[step]) {
        const card = cards[step] as HTMLElement;
        const cardLeft = card.offsetLeft;
        const cardWidth = card.offsetWidth;
        const containerWidth = container.offsetWidth;
        const scrollPosition = cardLeft - (containerWidth / 2) + (cardWidth / 2);
        
        container.scrollTo({
          left: scrollPosition,
          behavior: 'smooth'
        });
      }
    }
  };

  // Função para fazer scroll da seção de informações para o topo
  const scrollInfoToTop = () => {
    if (infoSectionRef.current) {
      infoSectionRef.current.scrollTo({
        top: 0,
        behavior: 'smooth'
      });
    }
  };

  // Effect para fazer scroll quando o step mudar
  useEffect(() => {
    // Pequeno delay para garantir que o DOM foi atualizado
    const timer = setTimeout(() => {
      scrollToCurrentColumn(currentStep);
      scrollInfoToTop();
    }, 100);
    return () => clearTimeout(timer);
  }, [currentStep]);

  const handleNext = () => {
    const nextStep = Math.min(stepInfo.length - 1, currentStep + 1);
    setCurrentStep(nextStep);
  };

  const handlePrevious = () => {
    const prevStep = Math.max(0, currentStep - 1);
    setCurrentStep(prevStep);
  };

  return (
    <div className="fixed inset-0 bg-white z-[9999] flex flex-col overflow-hidden">
      {/* Header */}
      <div className="px-6 py-3 border-b border-gray-200 flex items-center justify-between bg-white shadow-sm">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Manual de Leads</h2>
        </div>
        <button
          onClick={onClose}
          className="text-gray-400 hover:text-gray-600 transition-colors p-2 hover:bg-gray-100 rounded-lg"
        >
          <X size={24} />
        </button>
      </div>

      {/* Content - Flex layout para ocupar espaço disponível */}
      <div className="flex-1 overflow-hidden flex flex-col">
        {/* Pipeline Visualization Section */}
        <div className="px-3 sm:px-6 py-4 bg-gray-50 border-b border-gray-200">
          <div className="flex items-center justify-center mb-4">
            {/* Navigation buttons */}
            <div className="flex items-center gap-2 sm:gap-3">
              <button
                onClick={handlePrevious}
                disabled={currentStep === 0}
                className={`flex items-center gap-1 sm:gap-2 px-2 sm:px-4 py-1.5 sm:py-2 rounded-lg transition-colors text-xs sm:text-sm ${
                  currentStep === 0
                    ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                    : 'bg-white text-gray-700 hover:bg-gray-100 border border-gray-300'
                }`}
              >
                <ArrowLeft size={14} className="sm:w-4 sm:h-4" />
                <span className="hidden sm:inline">Anterior</span>
              </button>

              {/* Step indicators */}
              <div className="flex items-center gap-1.5 sm:gap-2 bg-white px-2 sm:px-3 py-1.5 sm:py-2 rounded-lg border border-gray-300">
                {stepInfo.map((_, index) => (
                  <button
                    key={index}
                    onClick={() => setCurrentStep(index)}
                    className={`h-1.5 sm:h-2 rounded-full transition-all ${
                      index === currentStep
                        ? 'bg-blue-600 w-6 sm:w-8'
                        : 'bg-gray-300 hover:bg-gray-400 w-1.5 sm:w-2'
                    }`}
                    title={stepInfo[index].title}
                  />
                ))}
              </div>

              <button
                onClick={handleNext}
                disabled={currentStep === stepInfo.length - 1}
                className={`flex items-center gap-1 sm:gap-2 px-2 sm:px-4 py-1.5 sm:py-2 rounded-lg transition-colors text-xs sm:text-sm ${
                  currentStep === stepInfo.length - 1
                    ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                    : 'bg-blue-600 text-white hover:bg-blue-700'
                }`}
              >
                <span className="hidden sm:inline">Próximo</span>
                <ArrowRight size={14} className="sm:w-4 sm:h-4" />
              </button>
            </div>
          </div>
          
          {/* Pipeline Cards */}
          <div 
            ref={pipelineScrollRef}
            className="overflow-x-auto pb-2 -mx-3 sm:mx-0"
          >
            <div className="flex gap-2 sm:gap-4 min-w-max px-3 sm:px-0">
              {statusOrder.map((status, index) => {
                const config = statusConfig[status];
                const isCurrent = status === currentStatus;
                const hasLead = index === currentIndex; // Lead aparece apenas na etapa atual
                
                return (
                  <div 
                    key={status}
                    data-pipeline-card
                    className={`flex-shrink-0 w-44 sm:w-56 rounded-lg border-2 transition-all ${
                      isCurrent ? 'border-blue-500 shadow-xl sm:scale-105' : 'border-gray-200'
                    }`}
                  >
                    <div className={`${config.bgColor} ${config.color} px-2 sm:px-4 py-2 sm:py-3 rounded-t-lg border-b border-gray-200`}>
                      <div className="flex items-center justify-between gap-1">
                        <h4 className="font-semibold text-[10px] sm:text-sm truncate flex-1">{config.label}</h4>
                        <span className={`${config.color} text-[9px] sm:text-xs font-medium bg-white px-1 sm:px-2 py-0.5 sm:py-1 rounded-full flex-shrink-0`}>
                          {hasLead ? '1' : '0'}
                        </span>
                      </div>
                    </div>
                    <div className="p-2 sm:p-3 bg-white rounded-b-lg min-h-[150px] sm:min-h-[180px]">
                      {hasLead && (
                        <div className={`bg-white rounded-lg border-2 ${
                          isCurrent ? 'border-blue-500 shadow-lg' : 'border-gray-200'
                        } p-2 sm:p-3 transition-all`}>
                          <div className="flex items-center gap-1.5 sm:gap-2 mb-2">
                            <div className="w-6 h-6 sm:w-8 sm:h-8 bg-green-500 rounded-full flex items-center justify-center text-white font-bold text-[10px] sm:text-sm flex-shrink-0">
                              JD
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-xs sm:text-sm font-medium text-gray-900 truncate">João da Silva</p>
                              <p className="text-[10px] sm:text-xs text-gray-500 truncate">joao@email.com</p>
                            </div>
                          </div>
                          <div className="flex items-center justify-between gap-1 mt-2 pt-2 border-t border-gray-100">
                            <button
                              disabled={index === 0}
                              className={`flex-1 px-1 sm:px-2 py-0.5 sm:py-1 text-[10px] sm:text-xs rounded transition-colors ${
                                index === 0
                                  ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                              }`}
                              title="Mover para esquerda"
                            >
                              ←
                            </button>
                            <button
                              disabled={index === statusOrder.length - 1}
                              className={`flex-1 px-1 sm:px-2 py-0.5 sm:py-1 text-[10px] sm:text-xs rounded transition-colors ${
                                index === statusOrder.length - 1
                                  ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                              }`}
                              title="Mover para direita"
                            >
                              →
                            </button>
                          </div>
                        </div>
                      )}
                      {!hasLead && (
                        <div className="text-center py-8 sm:py-10 text-gray-400 text-xs sm:text-sm">
                          Nenhum lead
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Step Information Section - Scrollable */}
        <div ref={infoSectionRef} className="flex-1 overflow-y-auto p-6">
          <div className="max-w-4xl mx-auto">
            <div className="bg-gradient-to-br from-blue-50 to-indigo-50 border border-blue-200 rounded-lg p-6 shadow-sm">
              <div className="flex items-start gap-4 mb-4">
                <div className={`${statusConfig[currentStatus].bgColor} ${statusConfig[currentStatus].color} px-4 py-2 rounded-lg font-semibold text-sm whitespace-nowrap`}>
                  {stepInfo[currentStep].title}
                </div>
              </div>
              
              <p className="text-gray-800 mb-5 text-base leading-relaxed">{stepInfo[currentStep].description}</p>
              
              <div className="mb-5">
                <h4 className="font-semibold text-gray-900 mb-3 flex items-center gap-2">
                  <CheckCircle2 size={18} className="text-green-600" />
                  Vantagens desta etapa:
                </h4>
                <ul className="space-y-2.5">
                  {stepInfo[currentStep].advantages.map((advantage, idx) => (
                    <li key={idx} className="flex items-start gap-3 text-sm text-gray-700 bg-white rounded-lg p-3 border border-blue-100">
                      <CheckCircle2 size={16} className="text-green-600 mt-0.5 flex-shrink-0" />
                      <span className="flex-1">{advantage}</span>
                    </li>
                  ))}
                </ul>
              </div>

              <div className="bg-white border-2 border-blue-400 rounded-lg p-4 shadow-sm">
                <p className="text-sm text-blue-900 font-medium flex items-start gap-2">
                  <span className="text-lg">💡</span>
                  <span><strong>Próxima ação:</strong> {stepInfo[currentStep].nextAction}</span>
                </p>
              </div>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}

