  // Função auxiliar para normalizar datas para comparação
  const normalizarData = (date: any): string | null => {
    if (!date) return null;
    if (date instanceof Date) {
      return date.toISOString().split('T')[0];
    }
    if (date.toDate && typeof date.toDate === 'function') {
      return date.toDate().toISOString().split('T')[0];
    }
    if (typeof date === 'string') {
      return new Date(date).toISOString().split('T')[0];
    }
    return null;
  };

  // Função para verificar se o planoTerapeutico foi alterado
  const planoTerapeuticoFoiAlterado = (planoOriginal: any, planoAtual: any): boolean => {
    if (!planoOriginal && !planoAtual) return false;
    if (!planoOriginal || !planoAtual) return true;
    
    // Comparar campos principais do plano terapêutico
    if (normalizarData(planoOriginal.startDate) !== normalizarData(planoAtual.startDate)) {
      return true;
    }
    
    if (planoOriginal.numeroSemanasTratamento !== planoAtual.numeroSemanasTratamento) {
      return true;
    }
    
    if (planoOriginal.injectionDayOfWeek !== planoAtual.injectionDayOfWeek) {
      return true;
    }
    
    if (planoOriginal.currentDoseMg !== planoAtual.currentDoseMg) {
      return true;
    }
    
    if (normalizarData(planoOriginal.lastDoseChangeAt) !== normalizarData(planoAtual.lastDoseChangeAt)) {
      return true;
    }
    
    if (normalizarData(planoOriginal.nextReviewDate) !== normalizarData(planoAtual.nextReviewDate)) {
      return true;
    }
    
    // Comparar metas se existirem
    if (JSON.stringify(planoOriginal.metas || {}) !== JSON.stringify(planoAtual.metas || {})) {
      return true;
    }
    
    // Comparar semanas canceladas
    const semanasOriginais = JSON.stringify((planoOriginal.semanasCanceladas || []).sort());
    const semanasAtuais = JSON.stringify((planoAtual.semanasCanceladas || []).sort());
    if (semanasOriginais !== semanasAtuais) {
      return true;
    }
    
    return false;
  };

  // Função para enviar e-mail de plano editado se necessário
  const enviarEmailSePlanoAlterado = async (pacienteId: string, planoAtual: any) => {
    if (!pacienteEditandoOriginal) return;
    
    const planoOriginal = pacienteEditandoOriginal.planoTerapeutico || {};
    const houveAlteracao = planoTerapeuticoFoiAlterado(planoOriginal, planoAtual);
    
    if (houveAlteracao && planoAtual && (planoAtual.startDate || planoAtual.numeroSemanasTratamento)) {
      try {
        await fetch('/api/send-email-plano-editado', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ pacienteId }),
        });
      } catch (emailError) {
        console.error('Erro ao enviar e-mail de plano editado:', emailError);
        // Não bloquear o fluxo se o e-mail falhar
      }
    }
  };
  
