  const buscaCalendarioDeferida = useDeferredValue(buscaPacienteCalendario);
  const sugestoesListaCalendario = useMemo(() => {
    const q = normTextoBuscaCal(buscaPacienteCalendario);
    if (!q || pacientes.length === 0) return [];
    const matches: string[] = [];
    const seen = new Set<string>();
    for (let i = 0; i < pacientes.length; i++) {
      const p = pacientes[i];
      const nome = (p.nome || p.dadosIdentificacao?.nomeCompleto || '').trim();
      if (!nome) continue;
      const nn = normTextoBuscaCal(nome);
      if (!nn.includes(q)) continue;
      if (seen.has(nome)) continue;
      seen.add(nome);
      matches.push(nome);
    }
    matches.sort((a, b) => {
      const na = normTextoBuscaCal(a);
      const nb = normTextoBuscaCal(b);
      const pa = na.startsWith(q) ? 0 : 1;
      const pb = nb.startsWith(q) ? 0 : 1;
      if (pa !== pb) return pa - pb;
      return a.localeCompare(b, 'pt-BR');
    });
    return matches.slice(0, 10);
  }, [buscaPacienteCalendario, pacientes]);
