  const processarArquivoExameLaboratorialIa = useCallback(async (file: File, target: 'desktop' | 'mobile') => {
    const setUploading = target === 'desktop' ? setExameIaUploadingDesktop : setExameIaUploadingMobile;
    const setFeedback = target === 'desktop' ? setExameIaFeedbackDesktop : setExameIaFeedbackMobile;
    const applyDate =
      target === 'desktop' ? indiceExameEditando === null : indiceExameEditandoMobile === null;

    setUploading(true);
    setFeedback({ type: 'idle' });
    try {
      const fd = new FormData();
      fd.append('file', file);
      const res = await fetch('/api/metaadmin/exames-laboratoriais-extrair-ia', { method: 'POST', body: fd });
      const json = (await res.json()) as { ok?: boolean; error?: string; data?: unknown };
      if (!res.ok || !json.ok) {
        setFeedback({ type: 'error', text: json.error || 'Não foi possível ler o arquivo.' });
        return;
      }
      const normalized = normalizarRespostaExameIA(json.data);
      if (target === 'desktop') {
        setNovoExameData((prev) =>
          applyExameExtraidoToForm(prev as NovoExameFormState, normalized, { applyDate })
        );
      } else {
        setNovoExameDataMobile((prev) =>
          applyExameExtraidoToForm(prev as NovoExameFormState, normalized, { applyDate })
        );
      }
      const n = Object.keys(normalized.camposMapeados).length;
      const parts: string[] = [];
      if (n > 0) {
        parts.push(`${n} campo(s) sugerido(s) pela IA. Revise antes de salvar.`);
      } else {
        parts.push('Nenhum valor mapeado com segurança. Você pode preencher manualmente.');
      }
      if (normalized.avisos.length > 0) parts.push(normalized.avisos.join(' '));
      setFeedback({ type: 'success', text: parts.join(' ') });

      if (normalized.examesNaoMapeados.length > 0) {
        setModalType('info');
        setModalMessage(buildMensagemExamesNaoInseridos(normalized.examesNaoMapeados));
        setShowMessageModal(true);
      }
    } catch (e) {
      setFeedback({
        type: 'error',
        text: e instanceof Error ? e.message : 'Erro ao enviar arquivo.',
      });
    } finally {
      setUploading(false);
    }
  }, [indiceExameEditando, indiceExameEditandoMobile]);

