  // Função para carregar pacientes do médico

  // Carregar pagamentos apenas dos pacientes do médico
  const loadPagamentos = useCallback(async (pacientesParaFiltrar?: PacienteCompleto[]) => {
    if (!medicoPerfil) return;
    
    try {
      // Usar pacientes passados como parâmetro ou do estado
      const pacientesParaUsar = pacientesParaFiltrar || pacientes;
      
      console.log('💰 Financeiro: Carregando pagamentos para', pacientesParaUsar.length, 'pacientes');
      
      // Se não há pacientes, não fazer nada (preservar pagamentos existentes)
      // Só limpar se explicitamente solicitado ou se realmente não houver pacientes
      if (pacientesParaUsar.length === 0) {
        console.log('💰 Financeiro: Nenhum paciente para filtrar, mantendo pagamentos existentes');
        return;
      }
      
      // Buscar todos os pagamentos
      const todosPagamentos = await PagamentoService.getAllPagamentos();
      console.log('💰 Financeiro: Total de pagamentos encontrados:', Object.keys(todosPagamentos).length);
      
      // Filtrar apenas pagamentos dos pacientes deste médico
      const pacientesIds = pacientesParaUsar.map(p => p.id);
      console.log('💰 Financeiro: IDs dos pacientes do médico:', pacientesIds);
      
      const pagamentosFiltrados: Record<string, PagamentoPaciente> = {};
      
      Object.entries(todosPagamentos).forEach(([pacienteId, pagamento]) => {
        if (pacientesIds.includes(pacienteId)) {
          pagamentosFiltrados[pacienteId] = pagamento;
        }
      });
      
      console.log('💰 Financeiro: Pagamentos filtrados encontrados:', Object.keys(pagamentosFiltrados).length);
      setPagamentosPacientes(pagamentosFiltrados);
    } catch (error) {
      console.error('Erro ao carregar pagamentos:', error);
      // Não limpar em caso de erro para preservar dados existentes
    }
  }, [medicoPerfil, pacientes]);

  // Carregar vendas avulsas apenas do médico
  const loadVendasAvulsas = useCallback(async () => {
    if (!medicoPerfil) return;
    
    try {
      const vendas = await PagamentoService.getAllVendasAvulsas(medicoPerfil.id);
      setVendasAvulsas(vendas || []);
    } catch (error) {
      console.error('Erro ao carregar vendas avulsas:', error);
      setVendasAvulsas([]);
    }
  }, [medicoPerfil]);

  const loadPacientes = useCallback(async () => {
    if (!user || !medicoPerfil) return;
    
    setLoadingPacientes(true);
    try {
      console.log('Carregando pacientes para médico ID:', medicoPerfil.id);
      
      // ==========================================
      // FASE 1: CARREGAR DADOS ESSENCIAIS (RÁPIDO)
      // ==========================================
      const pacientesData = await PacienteService.getPacientesByMedico(medicoPerfil.id);
      console.log('Pacientes encontrados:', pacientesData);
      
      // Renderizar pacientes imediatamente (sem esperar dados secundários)
      setPacientes(pacientesData);

      // Verificar se tem paciente com mais de 2 semanas (para mostrar NPS) - cálculo rápido
      const temSemana2 = pacientesData.some(p => {
        const semanaAtual = calcularSemanaAtualTratamento(p);
        return semanaAtual !== null && semanaAtual > 2;
      });
      setTemPacienteSemana2(temSemana2);

      // ==========================================
      // FASE 2: CARREGAR DADOS SECUNDÁRIOS EM PARALELO
      // ==========================================
      // Todas as operações pesadas executam em paralelo usando Promise.all
      
      const [
        mensagensResult,
        fotosResult,
        npsResult,
        nutricaoResult,
        pagamentosResult
      ] = await Promise.allSettled([
        // 1. Mensagens não lidas - paralelizado
        (async () => {
          const mensagensNaoLidasMap: Record<string, number> = {};
          const mensagensPromises = pacientesData
            .filter(p => p.email)
            .map(async (paciente) => {
              try {
                const count = await PacienteMensagemService.contarMensagensNaoLidasPacienteParaMedico(
                  medicoPerfil.id,
                  paciente.email!
                );
                if (count > 0) {
                  mensagensNaoLidasMap[paciente.id] = count;
                }
              } catch (error) {
                console.error(`Erro ao contar mensagens não lidas para paciente ${paciente.id}:`, error);
              }
            });
          await Promise.all(mensagensPromises);
          return mensagensNaoLidasMap;
        })(),
        
        // 2. Fotos dos pacientes
        (async () => {
          const userIds = pacientesData.map(p => p.userId).filter(Boolean);
          if (userIds.length === 0) return {};
          
          try {
            const response = await fetch('/api/user-photo', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ userIds })
            });
            if (response.ok) {
              const { photos } = await response.json();
              return photos;
            }
            return {};
          } catch (error) {
            console.error('Erro ao buscar fotos dos pacientes:', error);
            return {};
          }
        })(),
        
        // 3. NPS - OTIMIZADO: usar getRespostasPorMedico em vez de queries individuais
        (async () => {
          try {
            // Buscar todas as respostas NPS do médico de uma vez (1 query ao invés de 24)
            const respostasNPS = await NPSService.getRespostasPorMedico(medicoPerfil.id);
            
            // Criar mapa de userId -> tem resposta
            const npsMap: Record<string, boolean> = {};
            const userIdsComNPS = new Set(respostasNPS.map(r => r.userId));
            
            // Inicializar todos os pacientes como false
            pacientesData.forEach(p => {
              npsMap[p.id] = false;
            });
            
            // Marcar pacientes que têm NPS
            pacientesData.forEach(p => {
              if (p.userId && userIdsComNPS.has(p.userId)) {
                npsMap[p.id] = true;
              }
            });
            
            return npsMap;
          } catch (error) {
            console.error('Erro ao buscar NPS dos pacientes:', error);
            // Retornar mapa vazio em caso de erro
            return pacientesData.reduce((acc, p) => {
              acc[p.id] = false;
              return acc;
            }, {} as Record<string, boolean>);
          }
        })(),
        
        // 4. Verificação de nutrição - paralelizado
        (async () => {
          const nutricaoMap: Record<string, boolean> = {};
          const nutricaoPromises = pacientesData.map(async (paciente) => {
            try {
              const planoRef = doc(db, 'pacientes_completos', paciente.id, 'nutricao', 'plano');
              const planoSnap = await getDoc(planoRef);
              nutricaoMap[paciente.id] = planoSnap.exists();
            } catch (error) {
              console.error(`Erro ao verificar nutrição do paciente ${paciente.id}:`, error);
              nutricaoMap[paciente.id] = false;
            }
          });
          await Promise.all(nutricaoPromises);
          return nutricaoMap;
        })(),
        
        // 5. Pagamentos (não precisa await aqui, já será chamado depois)
        Promise.resolve(null)
      ]);

      // Processar resultados
      if (mensagensResult.status === 'fulfilled') {
        setMensagensNaoLidasPorPaciente(mensagensResult.value);
      } else {
        console.error('Erro ao carregar mensagens:', mensagensResult.reason);
        setMensagensNaoLidasPorPaciente({});
      }

      if (fotosResult.status === 'fulfilled') {
        setFotosPacientes(fotosResult.value);
      } else {
        console.error('Erro ao carregar fotos:', fotosResult.reason);
      }

      if (npsResult.status === 'fulfilled') {
        setNpsRespondidoPorPaciente(npsResult.value);
      } else {
        console.error('Erro ao carregar NPS:', npsResult.reason);
        // Inicializar como false para todos
        setNpsRespondidoPorPaciente(
          pacientesData.reduce((acc, p) => {
            acc[p.id] = false;
            return acc;
          }, {} as Record<string, boolean>)
        );
      }

      if (nutricaoResult.status === 'fulfilled') {
        setPacientesComNutricao(nutricaoResult.value);
      } else {
        console.error('Erro ao carregar nutrição:', nutricaoResult.reason);
        setPacientesComNutricao({});
      }
      
      // Carregar pagamentos após pacientes carregarem (passar pacientes como parâmetro)
      loadPagamentosChamadoPorLoadPacientes.current = true;
      await loadPagamentos(pacientesData);
      // Resetar a flag após um pequeno delay para permitir que o useEffect também possa executar se necessário
      setTimeout(() => {
        loadPagamentosChamadoPorLoadPacientes.current = false;
      }, 500);
    } catch (error) {
      console.error('Erro ao carregar pacientes:', error);
    } finally {
      setLoadingPacientes(false);
    }
  }, [user, medicoPerfil]);

  /** Preserva conclusão/depoimento em historicoConclusoesTratamento antes de limpar o ciclo atual.
   *  @param estrelasSnapshot se definido (inclui null), usa esse valor; senão lê do estado local. */
  const planoTerapeuticoAoReabrirPosConclusao = useCallback(
    (
      paciente: PacienteCompleto,
      evolucaoParaSnapshot: PacienteCompleto['evolucaoSeguimento'],
      estrelasSnapshot?: number | null
    ): PacienteCompleto['planoTerapeutico'] => {
      const plano = paciente.planoTerapeutico;
      const ct = plano?.conclusaoTratamento as Record<string, unknown> | undefined;
      let base: Record<string, unknown> = { ...(plano as Record<string, unknown>) };
      if (ct && deveArquivarConclusao(ct)) {
        const est =
          estrelasSnapshot !== undefined
            ? estrelasSnapshot
            : (estrelasDepoimentoPorPaciente[paciente.id] ??
              classificacaoEstrelasMobile[paciente.id] ??
              null);
        const snap = snapshotConclusaoParaHistorico(ct, {
          estrelas: typeof est === 'number' ? est : null,
          evolucaoSeguimento: (evolucaoParaSnapshot || []) as unknown[],
        });
        base = mergeHistoricoConclusaoNoPlano(base, snap);
      }
      return { ...base, conclusaoTratamento: null } as PacienteCompleto['planoTerapeutico'];
    },
    [estrelasDepoimentoPorPaciente, classificacaoEstrelasMobile]
  );

  const fetchEstrelasConclusaoPaciente = useCallback(
    async (pacienteId: string, medicoId: string): Promise<number | null> => {
      try {
        const r = await fetch(
          `/api/conclusao/classificacao-paciente?pacienteId=${encodeURIComponent(pacienteId)}&medicoId=${encodeURIComponent(medicoId)}`
        );
        if (!r.ok) return null;
        const j = (await r.json()) as { estrelas?: number | null };
        return typeof j.estrelas === 'number' ? j.estrelas : null;
      } catch {
        return null;
      }
    },
    []
  );

  const handleStatusTratamentoSelectChangeMobile = useCallback(async (e: ChangeEvent<HTMLSelectElement>) => {
    if (!pacienteEditando) return;
    const novoStatus = e.target.value as 'pendente' | 'em_tratamento' | 'concluido' | 'abandono';
    const labelNovo = novoStatus === 'em_tratamento' ? 'Em Tratamento' : novoStatus === 'pendente' ? 'Pendente' : novoStatus === 'abandono' ? 'Abandono' : 'Concluído';

    if (novoStatus === 'abandono' && pacienteEditando.statusTratamento !== 'abandono') {
      if (pacienteEditando.statusTratamento === 'concluido') {
        const querApagar = window.confirm('O paciente está Concluído. Deseja apagar o último registro de Conclusão e alterar o status para Abandono? Se não, o paciente continuará como Concluído.');
        if (!querApagar) return;
      }
      setStatusAnteriorAntesAbandono(pacienteEditando.statusTratamento || 'pendente');
      setMotivoAbandonoMedico('');
      setShowModalAbandonoMedico(true);
    } else if (novoStatus === 'concluido' && pacienteEditando.statusTratamento !== 'concluido') {
      setStatusAnteriorAntesConclusao(pacienteEditando.statusTratamento || 'pendente');
      const conclusaoExistenteMobile = pacienteEditando.planoTerapeutico?.conclusaoTratamento;
      const ultimoRegistroConclusaoMobile = (pacienteEditando.evolucaoSeguimento || []).filter((ev: any) =>
        (ev.id && String(ev.id).startsWith('seguimento-conclusao-')) || (ev.comentarioMedico && String(ev.comentarioMedico).toLowerCase().includes('conclusão'))
      ).pop();
      setDadosConclusao({
        pesoFinal: conclusaoExistenteMobile?.pesoFinalKg?.toString() ?? ultimoRegistroConclusaoMobile?.peso?.toString() ?? '',
        circunferenciaAbdominalFinal: ultimoRegistroConclusaoMobile?.circunferenciaAbdominal?.toString() ?? '',
        hba1cFinal: ultimoRegistroConclusaoMobile?.hba1c?.toString() ?? ''
      });
      setShowModalConclusaoMedico(true);
    } else {
      if (pacienteEditando.statusTratamento === 'concluido' && (novoStatus === 'em_tratamento' || novoStatus === 'pendente')) {
        const querApagar = window.confirm(
          `O paciente está Concluído. Deseja reabrir o tratamento (status "${labelNovo}")? O registro de conclusão será removido da evolução atual, mas depoimento e dados da conclusão ficarão guardados no histórico do paciente.`
        );
        if (!querApagar) return;
      }
      let evolucaoAtualizada = pacienteEditando.evolucaoSeguimento || [];
      if (pacienteEditando.statusTratamento === 'concluido' && (novoStatus === 'em_tratamento' || novoStatus === 'pendente')) {
        const evolucaoAntes = pacienteEditando.evolucaoSeguimento || [];
        const isRegistroConclusao = (ev: any) =>
          (ev.id && String(ev.id).startsWith('seguimento-conclusao-')) ||
          (ev.comentarioMedico && String(ev.comentarioMedico).normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().includes('conclusao'));
        const indicesConclusao = evolucaoAtualizada.map((ev: any, i: number) => ({ ev, i })).filter(({ ev }) => isRegistroConclusao(ev));
        const ultimoConclusao = indicesConclusao[indicesConclusao.length - 1];
        if (ultimoConclusao !== undefined) {
          evolucaoAtualizada = evolucaoAtualizada.filter((_: any, i: number) => i !== ultimoConclusao.i);
        }
        const fromState =
          estrelasDepoimentoPorPaciente[pacienteEditando.id] ?? classificacaoEstrelasMobile[pacienteEditando.id];
        let estArq: number | null | undefined =
          typeof fromState === 'number' ? fromState : undefined;
        if (estArq === undefined && medicoPerfil?.id) {
          estArq = await fetchEstrelasConclusaoPaciente(pacienteEditando.id, medicoPerfil.id);
        }
        setPacienteEditando({
          ...pacienteEditando,
          statusTratamento: novoStatus,
          evolucaoSeguimento: evolucaoAtualizada,
          planoTerapeutico: planoTerapeuticoAoReabrirPosConclusao(pacienteEditando, evolucaoAntes, estArq),
        });
      } else {
        setPacienteEditando({
          ...pacienteEditando,
          statusTratamento: novoStatus,
          evolucaoSeguimento: evolucaoAtualizada
        });
      }
    }
  }, [
    pacienteEditando,
    planoTerapeuticoAoReabrirPosConclusao,
    medicoPerfil?.id,
    estrelasDepoimentoPorPaciente,
    classificacaoEstrelasMobile,
    fetchEstrelasConclusaoPaciente,
  ]);

