  // Função para carregar nutricionistas elegíveis (verificados, ativos e vinculados ao médico)
  const loadNutricionistasElegiveis = useCallback(async () => {
    if (!medicoPerfil?.id) return;
    
    setLoadingNutricionistasElegiveis(true);
    try {
      const todosNutris = await NutricionistaService.getAllNutricionistas();
      // Filtrar: verificados, ativos e vinculados ao médico atual (para a lista de elegíveis)
      const elegiveis = todosNutris.filter(nutri => 
        nutri.isVerificado && 
        nutri.status === 'ativo' && 
        nutri.medicoVinculadoIds.includes(medicoPerfil.id)
      );
      setNutricionistasElegiveis(elegiveis);
      
      // Para o modal de busca, extrair estados e cidades de TODOS os nutricionistas verificados e ativos
      // (não apenas os já vinculados), para permitir buscar novos nutricionistas
      const todosVerificadosAtivos = todosNutris.filter(nutri => 
        nutri.isVerificado && nutri.status === 'ativo'
      );
      
      const estadosComNutri = new Set<string>();
      const cidadesComNutri: { estado: string; cidade: string }[] = [];
      
      todosVerificadosAtivos.forEach(nutri => {
        // Verificar se cidades existe e é um array antes de iterar
        if (nutri.cidades && Array.isArray(nutri.cidades)) {
          nutri.cidades.forEach(cidade => {
            estadosComNutri.add(cidade.estado);
            // Adicionar cidade se ainda não existir para este estado
            if (!cidadesComNutri.some(c => c.estado === cidade.estado && c.cidade === cidade.cidade)) {
              cidadesComNutri.push({
                estado: cidade.estado,
                cidade: cidade.cidade
              });
            }
          });
        }
      });
      
      setEstadosComNutricionistas(Array.from(estadosComNutri).sort());
      setCidadesComNutricionistas(cidadesComNutri);
    } catch (error) {
      console.error('Erro ao carregar nutricionistas elegíveis:', error);
    } finally {
      setLoadingNutricionistasElegiveis(false);
    }
  }, [medicoPerfil]);

  // Função para buscar nutricionistas por estado e cidade
  const buscarNutricionistasPorLocalizacao = useCallback(async () => {
    if (!estadoBuscaNutri || !cidadeBuscaNutri || !medicoPerfil?.id) return;
    
    setLoadingNutricionistasFiltrados(true);
    try {
      const todosNutris = await NutricionistaService.getAllNutricionistas();
      // Normalizar cidade para comparação (remover acentos, espaços extras, etc)
      const normalizarCidade = (cidade: string): string => {
        return cidade
          .toLowerCase()
          .trim()
          .normalize('NFD')
          .replace(/[\u0300-\u036f]/g, '') // Remove acentos
          .replace(/\s+/g, ' '); // Remove espaços extras
      };
      
      const cidadeBuscaNormalizada = normalizarCidade(cidadeBuscaNutri);
      
      // Filtrar: verificados, ativos (NÃO precisa estar vinculado) E que atendem na cidade selecionada
      // O objetivo é encontrar novos nutricionistas para compartilhar pacientes
      const filtrados = todosNutris.filter(nutri => {
        if (!nutri.isVerificado || nutri.status !== 'ativo') {
          return false;
        }
        
        // Verificar se o nutricionista atende na cidade selecionada
        // Verificar se cidades existe e é um array antes de usar .some()
        if (!nutri.cidades || !Array.isArray(nutri.cidades) || nutri.cidades.length === 0) {
          return false;
        }
        
        return nutri.cidades.some(c => {
          const cidadeNormalizada = normalizarCidade(c.cidade);
          return c.estado === estadoBuscaNutri && cidadeNormalizada === cidadeBuscaNormalizada;
        });
      });
      
      console.log('🔍 Busca de nutricionistas:', {
        estado: estadoBuscaNutri,
        cidade: cidadeBuscaNutri,
        totalNutris: todosNutris.length,
        filtrados: filtrados.length,
        nutricionistas: filtrados.map(n => ({ nome: n.nome, cidades: n.cidades }))
      });
      
      setNutricionistasFiltrados(filtrados);
    } catch (error) {
      console.error('Erro ao buscar nutricionistas:', error);
    } finally {
      setLoadingNutricionistasFiltrados(false);
    }
  }, [estadoBuscaNutri, cidadeBuscaNutri, medicoPerfil]);

