  // Função para carregar leads do médico
  const loadLeadsMedico = useCallback(async () => {
    if (!user || !medicoPerfil) return;
    
    setLoadingLeadsMedico(true);
    try {
      console.log('Carregando leads para médico ID:', medicoPerfil.id);
      
      // ==========================================
      // FASE 1: CARREGAR DADOS ESSENCIAIS (RÁPIDO)
      // ==========================================
      // Buscar leads existentes e solicitações em paralelo
      const [leadsExistentes, todasSolicitacoes] = await Promise.all([
        LeadMedicoService.getLeadsByMedico(medicoPerfil.id),
        SolicitacaoMedicoService.getSolicitacoesPorMedico(medicoPerfil.id)
      ]);
      
      console.log('Leads existentes encontrados:', leadsExistentes.length);
      console.log('Solicitações encontradas:', todasSolicitacoes.length);
      
      // Criar mapa de leads existentes por email para lookup rápido
      const leadsExistentesMap = new Map(leadsExistentes.map(l => [l.email.toLowerCase(), l]));
      
      // Renderizar leads existentes imediatamente (sem esperar processamento)
      const leadsPorStatusInicial: Record<LeadMedicoStatus, LeadMedico[]> = {
        nao_qualificado: [],
        enviado_contato: [],
        contato_feito: [],
        em_tratamento: [],
        excluido: [],
        concluido: [],
      };
      
      leadsExistentes.forEach(lead => {
        // Migrar leads com status 'aprovado' (removido) para 'enviado_contato'
        if ((lead.status as any) === 'aprovado') {
          lead.status = 'enviado_contato';
          lead.dataStatus = new Date();
          // Atualizar no Firestore em background
          LeadMedicoService.updateLeadStatus(lead.id, 'enviado_contato', user?.email || undefined).catch(console.error);
        }
        leadsPorStatusInicial[lead.status].push(lead);
      });
      
      // Ordenar cada coluna: estrelas desc, depois data de status desc
      Object.keys(leadsPorStatusInicial).forEach(status => {
        leadsPorStatusInicial[status as LeadMedicoStatus].sort((a, b) => {
          const estrelasA = a.estrelas || 0;
          const estrelasB = b.estrelas || 0;
          if (estrelasB !== estrelasA) return estrelasB - estrelasA;
          const dateA = a.dataStatus?.getTime() || 0;
          const dateB = b.dataStatus?.getTime() || 0;
          return dateB - dateA;
        });
      });
      
      // Renderizar leads existentes imediatamente
      setLeadsMedico(leadsExistentes);
      setLeadsByStatus(leadsPorStatusInicial);
      
      // ==========================================
      // FASE 2: PROCESSAR ATUALIZAÇÕES EM BACKGROUND
      // ==========================================
      if (todasSolicitacoes.length === 0) {
        setLoadingLeadsMedico(false);
        return;
      }
      
      // OTIMIZAÇÃO: Carregar apenas pacientes necessários (pelos IDs das solicitações)
      // em vez de carregar TODOS os pacientes do sistema
      const pacienteIdsUnicos = [...new Set(todasSolicitacoes
        .map(s => s.pacienteId)
        .filter(Boolean) as string[]
      )];
      
      // Carregar pacientes em paralelo
      const pacientesData = await Promise.all(
        pacienteIdsUnicos.map(id => PacienteService.getPacienteById(id))
      );
      
      const pacientesMap = new Map<string, PacienteCompleto>();
      pacientesData.forEach(p => {
        if (p) {
          // Criar múltiplas chaves para lookup flexível
          if (p.userId) pacientesMap.set(p.userId, p);
          if (p.email) pacientesMap.set(p.email.toLowerCase(), p);
          if (p.id) pacientesMap.set(p.id, p);
        }
      });
      
      // Processar solicitações e criar/atualizar leads EM PARALELO
      const leadsAtualizacoes = todasSolicitacoes.map(async (solicitacao) => {
        const email = solicitacao.pacienteEmail.toLowerCase();
        const paciente = pacientesMap.get(solicitacao.pacienteId || solicitacao.pacienteEmail?.toLowerCase() || '');
        const leadExistente = leadsExistentesMap.get(email);
        
        if (leadExistente) {
          // IMPORTANTE: Atualizar dados do lead existente (mas manter status)
          const leadAtualizado: LeadMedico = {
            ...leadExistente,
            name: solicitacao.pacienteNome,
            telefone: solicitacao.pacienteTelefone || paciente?.dadosIdentificacao?.telefone,
            cidade: paciente?.dadosIdentificacao?.endereco?.cidade,
            estado: paciente?.dadosIdentificacao?.endereco?.estado,
            solicitacaoId: solicitacao.id,
            // Preservar status e dataStatus exatamente como estão no Firestore
            status: leadExistente.status,
            dataStatus: leadExistente.dataStatus,
          };
          // Atualizar no Firestore (preservando o status)
          await LeadMedicoService.createOrUpdateLead(leadAtualizado);
          return leadAtualizado;
        } else {
          // Criar novo lead - SEMPRE começa em "não qualificado"
          const novoLead: Omit<LeadMedico, 'id'> = {
            uid: solicitacao.pacienteId || email,
            email: solicitacao.pacienteEmail,
            name: solicitacao.pacienteNome,
            telefone: solicitacao.pacienteTelefone || paciente?.dadosIdentificacao?.telefone,
            cidade: paciente?.dadosIdentificacao?.endereco?.cidade,
            estado: paciente?.dadosIdentificacao?.endereco?.estado,
            createdAt: solicitacao.criadoEm,
            emailVerified: true,
            status: 'nao_qualificado', // SEMPRE começa em não qualificado
            dataStatus: new Date(),
            medicoId: medicoPerfil.id,
            solicitacaoId: solicitacao.id,
          };
          const leadId = await LeadMedicoService.createOrUpdateLead(novoLead);
          return { ...novoLead, id: leadId } as LeadMedico;
        }
      });
      
      // Executar todas as atualizações em paralelo
      const leadsProcessados = await Promise.allSettled(leadsAtualizacoes);
      
      // Processar resultados
      const leadsFinais: LeadMedico[] = leadsProcessados
        .map((result, index) => {
          if (result.status === 'fulfilled') {
            return result.value;
          } else {
            console.error(`Erro ao processar lead da solicitação ${todasSolicitacoes[index].id}:`, result.reason);
            // Retornar lead existente se houver, senão null
            const email = todasSolicitacoes[index].pacienteEmail.toLowerCase();
            return leadsExistentesMap.get(email) || null;
          }
        })
        .filter((lead): lead is LeadMedico => lead !== null);
      
      // Organizar leads por status
      const leadsPorStatus: Record<LeadMedicoStatus, LeadMedico[]> = {
        nao_qualificado: [],
        enviado_contato: [],
        contato_feito: [],
        em_tratamento: [],
        excluido: [],
        concluido: [],
      };
      
      leadsFinais.forEach(lead => {
        // Migrar leads com status 'aprovado' (removido) para 'enviado_contato'
        if ((lead.status as any) === 'aprovado') {
          lead.status = 'enviado_contato';
          lead.dataStatus = new Date();
          // Atualizar no Firestore em background
          LeadMedicoService.updateLeadStatus(lead.id, 'enviado_contato', user?.email || undefined).catch(console.error);
        }
        leadsPorStatus[lead.status].push(lead);
      });
      
      // Ordenar cada coluna: estrelas desc, depois data de status desc
      Object.keys(leadsPorStatus).forEach(status => {
        leadsPorStatus[status as LeadMedicoStatus].sort((a, b) => {
          const estrelasA = a.estrelas || 0;
          const estrelasB = b.estrelas || 0;
          if (estrelasB !== estrelasA) return estrelasB - estrelasA;
          const dateA = a.dataStatus?.getTime() || 0;
          const dateB = b.dataStatus?.getTime() || 0;
          return dateB - dateA;
        });
      });
      
      // Atualizar com dados completos processados
      setLeadsMedico(leadsFinais);
      setLeadsByStatus(leadsPorStatus);
      console.log('Leads processados:', leadsFinais.length);
    } catch (error) {
      console.error('Erro ao carregar leads:', error);
    } finally {
      setLoadingLeadsMedico(false);
    }
  }, [user, medicoPerfil]);

  // Verificar se deve mostrar NPS (médico com paciente na 2ª semana)
  // Executar APENAS quando médicoPerfil e pacientes forem carregados E não estiver carregando
  useEffect(() => {
    // Aguardar até que o carregamento termine
    if (loadingPacientes) {
      console.log('NPS (médico): Aguardando carregamento dos pacientes...');
      setTemPacienteSemana2(false);
      return;
    }

    // Se não tiver dados necessários, não executar
    if (!user?.uid || !medicoPerfil?.id) {
      console.log('NPS (médico): Dados não disponíveis', { hasUser: !!user?.uid, hasMedico: !!medicoPerfil?.id });
      setTemPacienteSemana2(false);
      return;
    }

    const verificarNPS = async () => {
      console.log('NPS (médico): Verificando condições', { 
        hasUser: !!user?.uid, 
        hasMedico: !!medicoPerfil?.id,
        medicoNome: medicoPerfil.nome,
        pacientesCarregados: pacientes.length,
        loadingPacientes: false
      });

      // Verificar se já respondeu completamente no banco
      let npsRespondido = false;
      try {
        const resposta = await NPSService.getRespostaPorUserId(user.uid);
        if (resposta && NPSService.isRespostaCompleta(resposta)) {
          npsRespondido = true;
          setNpsJaRespondido(true);
          setTemPacienteSemana2(false);
          localStorage.setItem('nps_respondido', 'true');
          console.log('NPS (médico): Já respondido completamente');
          return;
        }
      } catch (error) {
        console.error('Erro ao verificar resposta NPS:', error);
      }

      // Verificar se tem paciente com semana > 2
      // Usar os pacientes já carregados (não buscar novamente)
      const temPacienteSemana2 = pacientes.some(p => {
        const semanaAtual = calcularSemanaAtualTratamento(p);
        console.log('NPS (médico): Paciente', p.nome, 'semana:', semanaAtual);
        const resultado = semanaAtual !== null && semanaAtual > 2;
        if (resultado) {
          console.log('NPS (médico): ✅ Paciente', p.nome, 'atende critério (semana > 2)');
        }
        return resultado;
      });
      console.log('NPS (médico): Tem paciente com semana > 2?', temPacienteSemana2);
      console.log('NPS (médico): Total de pacientes verificados:', pacientes.length);

      // Lógica simplificada:
      // Se algum paciente tem semana > 2 E NPS não respondido → mostra notificação
      // Se nenhum paciente tem semana > 2 → não mostra
      // Se algum paciente tem semana > 2 E NPS respondido → não mostra (já retornou acima)
      if (temPacienteSemana2 && !npsRespondido) {
        console.log('NPS (médico): ✅ Mostrando notificação (tem paciente semana > 2 e NPS não respondido)');
        setTemPacienteSemana2(true);
      } else {
        console.log('NPS (médico): ❌ Não mostrando notificação - temPacienteSemana2:', temPacienteSemana2, ', npsRespondido:', npsRespondido);
        setTemPacienteSemana2(false);
      }
    };

    verificarNPS();
  }, [user?.uid, medicoPerfil?.id, pacientes, loadingPacientes]);

