  // Ao fechar o modal de pagamento no Financeiro, recarrega pagamentos para o calendário e listas refletirem o servidor
  useEffect(() => {
    const fechou =
      showModalPagamentoEstavaAbertoRef.current &&
      !showModalPagamento &&
      activeMenu === 'financeiro' &&
      user &&
      medicoPerfil &&
      pacientes.length > 0;
    if (fechou) {
      void loadPagamentos(pacientes);
    }
    showModalPagamentoEstavaAbertoRef.current = showModalPagamento;
  }, [showModalPagamento, activeMenu, user, medicoPerfil, pacientes, loadPagamentos]);

  // Carregar "tem treinos" por paciente (ícone Personal rosa só quando há ao menos 1 treino)
  // trainingSessions usa patientId = Firebase UID; pacientes_completos.userId pode ser "uid_timestamp"
  useEffect(() => {
    if (activeMenu !== 'pacientes' || pacientes.length === 0) return;
    let cancelled = false;
    (async () => {
      const ids = new Set<string>();
      const BATCH = 10;
      const opts = { startDate: '2020-01-01' as const, endDate: '2030-12-31' as const };
      for (let i = 0; i < pacientes.length; i += BATCH) {
        if (cancelled) return;
        const batch = pacientes.slice(i, i + BATCH);
        const results = await Promise.all(
          batch.map(async (p) => {
            let has = false;
            const toTry: string[] = [];
            if (p.userId) toTry.push(p.userId);
            const prefix = /^(.+)_\d+$/.exec(p.userId || '')?.[1];
            if (prefix) toTry.push(prefix);
            if (p.id) toTry.push(p.id);
            for (const id of toTry) {
              if (has) break;
              try {
                const s = await trainingSessionService.getPatientSessions(id, opts);
                has = s.length > 0;
              } catch { /* ignore */ }
            }
            return { userId: p.userId, id: p.id, has };
          })
        );
        results.forEach((r, idx) => {
          if (r.has) {
            const p = batch[idx];
            if (p.userId) ids.add(p.userId);
            if (p.id) ids.add(p.id);
          }
        });
      }
      if (!cancelled) setPacientesComTreinos(ids);
    })();
    return () => { cancelled = true; };
  }, [activeMenu, pacientes]);

  /** Recarrega dados do Calendário (aplicações/pagamentos no grid + CalendarioTreinosPersonal via key). Chamado ao clicar no menu Calendário ou no botão Atualizar da página. */
  const refreshCalendarioDados = useCallback(() => {
    setCalendarioRefreshKey((k) => k + 1);
    void loadPacientes();
    void loadVendasAvulsas();
  }, [loadPacientes, loadVendasAvulsas]);

  // Atualizar calendário automaticamente a cada 25s quando visível (ex.: paciente preenche dados pelo link)
  useEffect(() => {
    if (!user || !medicoPerfil || activeMenu !== 'calendario') return;
    const interval = setInterval(() => {
      loadPacientes();
    }, 25000);
    return () => clearInterval(interval);
  }, [user, medicoPerfil, activeMenu, loadPacientes]);

  // Atualizar painel do dia no calendário quando pagamentos forem atualizados (ex: ao salvar edição no modal)
  // Garante que ao alterar data de pagamento, o calendário reflita a mudança tanto no grid quanto no painel lateral
  const obterPagamentosMesParaCalendario = useCallback((): Array<{
    data: Date;
    paciente: PacienteCompleto | { nome: string };
    parcela: ParcelaPagamento;
    tipoEvento?: 'dataVenda' | 'vencimento';
  }> => {
    const ano = mesCalendario.getFullYear();
    const mes = mesCalendario.getMonth();
    const mesInicio = new Date(ano, mes, 1);
    const mesFim = new Date(ano, mes + 1, 0);
    mesFim.setHours(23, 59, 59);
    const pagamentosDoMes: Array<{ data: Date; paciente: PacienteCompleto | { nome: string }; parcela: ParcelaPagamento; tipoEvento?: 'dataVenda' | 'vencimento' }> = [];
    const toDate = (v: unknown): Date | null => {
      if (!v) return null;
      if (v instanceof Date) return v;
      const t = (v as { toDate?: () => Date })?.toDate?.();
      if (t) return t;
      const d = new Date(v as string | number);
      return isNaN(d.getTime()) ? null : d;
    };
    const push = (data: Date, paciente: PacienteCompleto | { nome: string }, parcela: ParcelaPagamento, tipoEvento?: 'dataVenda' | 'vencimento') => {
      if (data >= mesInicio && data <= mesFim) pagamentosDoMes.push({ data, paciente, parcela, tipoEvento });
    };
    Object.entries(pagamentosPacientes || {}).forEach(([pacienteId, pagamento]) => {
      const paciente = pacientes.find(p => p.id === pacienteId);
      if (!paciente) return;
      if (pagamento.parcelas && pagamento.parcelas.length > 0) {
        let abertoSomado = 0;
        pagamento.parcelas.forEach(parcela => {
          if (parcela.status !== 'paga') abertoSomado += parcela.valor ?? 0;
          if (parcela.status === 'paga') {
            const dataPagParcela = toDate(parcela.dataPagamento);
            if (dataPagParcela) push(dataPagParcela, paciente, parcela);
          } else {
            const dataVencimento = toDate(parcela.dataVencimento);
            if (dataVencimento) push(dataVencimento, paciente, parcela);
          }
        });
        const { valorPendente } = getValoresPacienteDeParcelas(pagamento);
        if (valorPendente > abertoSomado) {
          const diff = valorPendente - abertoSomado;
          const dataVen = toDate(pagamento.dataVencimento);
          if (dataVen) push(dataVen, paciente, { numero: 0, valor: diff, dataVencimento: dataVen, status: 'pendente' });
        }
      } else {
        const dataPrevista = toDate(pagamento.dataVencimento);
        const dataPagamentoUnico = toDate(pagamento.dataPagamento);
        const { valorPendente, valorTotal } = getValoresPacienteDeParcelas(pagamento);
        if (dataPagamentoUnico && pagamento.statusPagamento === 'pago' && valorTotal > 0) {
          push(dataPagamentoUnico, paciente, { numero: 1, valor: valorTotal, dataVencimento: dataPagamentoUnico, status: 'paga' });
        }
        if (dataPrevista && (valorPendente > 0 || valorTotal > 0) && pagamento.statusPagamento !== 'pago') {
          push(dataPrevista, paciente, { numero: 1, valor: valorPendente || valorTotal, dataVencimento: dataPrevista, status: 'pendente' });
        }
      }
    });
    (vendasAvulsas || []).forEach(venda => {
      const nomeVenda = { nome: venda.cliente || venda.descricao || 'Venda avulsa' };
      if (venda.parcelas && venda.parcelas.length > 0) {
        let abertoSomado = 0;
        venda.parcelas.forEach(parcela => {
          if (parcela.status !== 'paga') abertoSomado += parcela.valor ?? 0;
          if (parcela.status === 'paga') {
            const dataPagParcela = toDate(parcela.dataPagamento);
            if (dataPagParcela) push(dataPagParcela, nomeVenda, parcela, 'vencimento');
          } else {
            const dataVencimento = toDate(parcela.dataVencimento);
            if (dataVencimento) push(dataVencimento, nomeVenda, parcela, 'vencimento');
          }
        });
        const valorPendente = venda.valorPendente ?? 0;
        if (valorPendente > abertoSomado) {
          const diff = valorPendente - abertoSomado;
          const dataVen = toDate(venda.dataVencimento);
          if (dataVen) push(dataVen, nomeVenda, { numero: 0, valor: diff, dataVencimento: dataVen, status: 'pendente' }, 'vencimento');
        }
      } else {
        const dataParaPagamento = venda.statusPagamento === 'pago' && toDate(venda.dataPagamento)
          ? toDate(venda.dataPagamento)
          : toDate(venda.dataVencimento);
        const valorPendente = venda.valorPendente ?? 0;
        const valorTotal = venda.valorTotal ?? 0;
        if (dataParaPagamento && (valorPendente > 0 || valorTotal > 0)) {
          push(dataParaPagamento, nomeVenda, { numero: 1, valor: valorPendente || valorTotal, dataVencimento: dataParaPagamento, status: venda.statusPagamento === 'pago' ? 'paga' : 'pendente' }, 'vencimento');
        }
      }
    });
    pagamentosDoMes.sort((a, b) => a.data.getTime() - b.data.getTime());
    return pagamentosDoMes;
  }, [pagamentosPacientes, vendasAvulsas, pacientes, mesCalendario]);

  // Calcular aplicações planejadas de um paciente para o mini calendário (mesma lógica da página Calendário)
  const calcularAplicacoesPacienteMini = useCallback((paciente: PacienteCompleto, mesInicio: Date, mesFim: Date): Array<{ data: Date; paciente: PacienteCompleto; semana: number; dose: number; localAplicacao: string }> => {
    const aplicacoes: Array<{ data: Date; paciente: PacienteCompleto; semana: number; dose: number; localAplicacao: string }> = [];
    const planoTerapeutico = paciente.planoTerapeutico;
    const primeiraDose = planoTerapeutico ? primeiraDoseDoPlano(planoTerapeutico) : null;
    if (!primeiraDose) return aplicacoes;
    const doseInicial = planoTerapeutico.currentDoseMg || 2.5;
    const evolucao = paciente.evolucaoSeguimento || [];
    const numeroSemanas = Number(planoTerapeutico.numeroSemanasTratamento) || 18;
    const semanasCanceladas = planoTerapeutico.semanasCanceladas || [];
    const locais = ['abdome', 'coxa', 'braco'];
    const calcularDoseComAtrasos = (semanaIndex: number) => {
      let semanasDesdeUltimoCiclo = semanaIndex;
      for (let s = 0; s < semanaIndex; s++) {
        const dataPrevista = new Date(primeiraDose);
        dataPrevista.setDate(primeiraDose.getDate() + (s * 7));
        const registro = evolucao.find(e => {
          if (!e.dataRegistro) return false;
          const dataRegistro = e.dataRegistro instanceof Date ? new Date(e.dataRegistro) : new Date((e.dataRegistro as any)?.toDate?.() || e.dataRegistro);
          if (isNaN(dataRegistro.getTime())) return false;
          dataRegistro.setHours(0, 0, 0, 0);
          const diffDias = Math.abs((dataRegistro.getTime() - dataPrevista.getTime()) / (1000 * 60 * 60 * 24));
          return diffDias <= 1;
        });
        if (registro?.dataRegistro) {
          const dataRegistro = registro.dataRegistro instanceof Date ? new Date(registro.dataRegistro) : new Date((registro.dataRegistro as any)?.toDate?.() || registro.dataRegistro);
          dataRegistro.setHours(0, 0, 0, 0);
          const diffDias = (dataRegistro.getTime() - dataPrevista.getTime()) / (1000 * 60 * 60 * 24);
          if (diffDias >= 4) {
            semanasDesdeUltimoCiclo = semanaIndex - s - 1;
            break;
          }
        }
      }
      return doseInicial + (Math.floor(semanasDesdeUltimoCiclo / 4) * 2.5);
    };
    const datasAplicacaoIndividuais = planoTerapeutico.datasAplicacaoIndividuais || {};
    for (let semana = 0; semana < numeroSemanas; semana++) {
      const semanaNum = semana + 1;
      if (semanasCanceladas.includes(semanaNum)) continue;
      let dataDose: Date;
      if (datasAplicacaoIndividuais[semanaNum]) {
        try {
          const [y, m, d] = datasAplicacaoIndividuais[semanaNum].split('-').map(Number);
          dataDose = new Date(y, m - 1, d);
        } catch {
          dataDose = new Date(primeiraDose);
          dataDose.setDate(primeiraDose.getDate() + (semana * 7));
        }
      } else {
        dataDose = new Date(primeiraDose);
        dataDose.setDate(primeiraDose.getDate() + (semana * 7));
      }
      if (dataDose >= mesInicio && dataDose <= mesFim) {
        let dosePlanejada: number;
        if (planoTerapeutico.esquemaDosesCustomizado?.[semanaNum]) {
          dosePlanejada = planoTerapeutico.esquemaDosesCustomizado[semanaNum];
        } else {
          dosePlanejada = calcularDoseComAtrasos(semana);
        }
        const dataSemanaAnterior = new Date(dataDose);
        dataSemanaAnterior.setDate(dataDose.getDate() - 7);
        const aplicacaoSemanaAnterior = evolucao.find(e => {
          const dataRegistro = e.dataRegistro instanceof Date ? new Date(e.dataRegistro) : new Date((e.dataRegistro as any)?.toDate?.() || e.dataRegistro);
          const diffDias = Math.abs((dataRegistro.getTime() - dataSemanaAnterior.getTime()) / (1000 * 60 * 60 * 24));
          return diffDias <= 1;
        });
        let ultimoLocalAplicado = aplicacaoSemanaAnterior?.localAplicacao;
        if (!ultimoLocalAplicado) {
          const ultimaAplicacao = evolucao
            .filter(e => {
              const dataRegistro = e.dataRegistro instanceof Date ? new Date(e.dataRegistro) : new Date((e.dataRegistro as any)?.toDate?.() || e.dataRegistro);
              return dataRegistro < dataDose;
            })
            .sort((a, b) => {
              const dataA = a.dataRegistro instanceof Date ? new Date(a.dataRegistro) : new Date((a.dataRegistro as any)?.toDate?.() || a.dataRegistro);
              const dataB = b.dataRegistro instanceof Date ? new Date(b.dataRegistro) : new Date((b.dataRegistro as any)?.toDate?.() || b.dataRegistro);
              return dataB.getTime() - dataA.getTime();
            })[0];
          ultimoLocalAplicado = ultimaAplicacao?.localAplicacao;
        }
        let localIndex = 0;
        if (ultimoLocalAplicado) {
          const ultimoLocalIndex = locais.indexOf(ultimoLocalAplicado);
          if (ultimoLocalIndex >= 0) localIndex = (ultimoLocalIndex + 1) % locais.length;
        }
        aplicacoes.push({ data: dataDose, paciente, semana: semanaNum, dose: dosePlanejada, localAplicacao: locais[localIndex] });
      }
    }
    return aplicacoes;
  }, []);

  const obterRegistroSeguimentoDaAplicacaoMini = useCallback((aplicacao: { data: Date; paciente: PacienteCompleto; semana: number }) => {
    const evolucao = aplicacao.paciente.evolucaoSeguimento || [];
    const dataPrevista = new Date(aplicacao.data);
    dataPrevista.setHours(0, 0, 0, 0);
    const registro = evolucao.find(e => {
      if (!e.dataRegistro) return false;
      const dataReg = e.dataRegistro instanceof Date ? new Date(e.dataRegistro) : new Date((e.dataRegistro as any)?.toDate?.() || e.dataRegistro);
      if (isNaN(dataReg.getTime())) return false;
      dataReg.setHours(0, 0, 0, 0);
      const diffDias = Math.abs((dataReg.getTime() - dataPrevista.getTime()) / (1000 * 60 * 60 * 24));
      return diffDias <= 3;
    });
    return registro ?? null;
  }, []);

