                            const cidadesCustomEstado = cidadesCustomizadas
                              .filter(c => c.estado === estadoSelecionado)
                              .map(c => c.cidade);
                            
                            const todasCidades = [...new Set([...cidadesPadrao, ...cidadesCustomEstado])].sort();
                            
